CREATE TABLE verification_levels (id SERIAL PRIMARY KEY, level_name VARCHAR(50) NOT NULL UNIQUE, max_daily_limit DECIMAL(15, 2) NOT NULL);
CREATE TABLE users (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, verification_level_id INTEGER REFERENCES verification_levels(id), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE projects (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, description TEXT, goal_amount DECIMAL(15, 2) NOT NULL, current_amount DECIMAL(15, 2) DEFAULT 0.00, owner_id INTEGER REFERENCES users(id), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE donations (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), project_id INTEGER REFERENCES projects(id), amount DECIMAL(15, 2) NOT NULL, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, risk_score DECIMAL(5, 2) DEFAULT 0.00);
CREATE TABLE expenses (id SERIAL PRIMARY KEY, project_id INTEGER REFERENCES projects(id), amount DECIMAL(15, 2) NOT NULL, category VARCHAR(100) NOT NULL, description TEXT, proof_url VARCHAR(500), timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE audit_logs (id SERIAL PRIMARY KEY, action_type VARCHAR(100) NOT NULL, entity_type VARCHAR(100) NOT NULL, entity_id INTEGER NOT NULL, details JSONB, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE risk_scores (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), transaction_id INTEGER, score DECIMAL(5, 2) NOT NULL, reason TEXT, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
